pragma solidity 0.8.27;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import { ReentrancyGuard } from "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import { ICarbonCoinDex } from "./interface/ICarbonCoinDex.sol";
import { ICarbonCoinConfig } from "./interface/ICarbonCoinConfig.sol";
import { ISomniaExchangeRouter02 } from "./interface/ISomniaExchangeRouter02.sol";
import { ISomniaExchangeFactory } from "./interface/ISomniaExchangeFactory.sol";
import { ISomniaExchangePair } from "./interface/ISomniaExchangePair.sol";

contract CarbonCoinDex is ICarbonCoinDex, ReentrancyGuard, Ownable {
    IERC20 public immutable USDC;
    address public config;
    ISomniaExchangeRouter02 public dexRouter;
    ISomniaExchangeFactory public factory;

    /**
     * @notice Constructor for the CarbonCoinDex contract.
     * @param _usdc The address of the USDC token contract.
     * @param _router The address of the Somnia Exchange V2 router.
     * @param _config The address of the token configuration contract.
     */
    constructor(
        address _usdc,
        address _router,
        address _config
    ) Ownable(_msgSender()) ReentrancyGuard() {
        require(_usdc != address(0), "Invalid USDC address");
        require(_router != address(0), "Invalid router");
        require(_config != address(0), "Invalid config");

        USDC = IERC20(_usdc);
        config = _config;
        dexRouter = ISomniaExchangeRouter02(_router);
        factory = ISomniaExchangeFactory(dexRouter.factory());
    }

    /**
     * @notice Deploy Liquidity to Somnia Exchange with USDC/Token pair.
     * @dev Creates a USDC/Token liquidity pool.
     */
    function deployLiquidity(address creator, address token, uint256 tokensAmount, uint256 usdcAmount)
        external
        onlyAuthorized(token)
        nonReentrant
        returns (uint256 amountA, uint256 amountB, uint256 liquidity)
    {
        require(IERC20(token).transferFrom(_msgSender(), address(this), tokensAmount), "Token transfer failed");
        require(USDC.transferFrom(_msgSender(), address(this), usdcAmount), "USDC transfer failed");

        IERC20(token).approve(address(dexRouter), tokensAmount);
        USDC.approve(address(dexRouter), usdcAmount);

        (amountA, amountB, liquidity) = dexRouter.addLiquidity(
            address(USDC),
            token,
            usdcAmount,
            tokensAmount,
            (usdcAmount * 95) / 100, // 5% slippage
            (tokensAmount * 95) / 100, // 5% slippage
            address(0x0),
            block.timestamp
        );

        address pair = factory.getPair(address(USDC), token);

        emit LiquidityDeployed(token, creator, pair, amountA, amountB, liquidity, block.timestamp);
    }

    function removeLiquidity(address token, address to, uint256 liquidity)
        external
        onlyAuthorized(token)
        nonReentrant
        returns (uint256 amountA, uint256 amountB)
    {
        require(to != address(0), "Invalid address");
        require(liquidity > 0, "Liquidity must be greater than 0");

        address pair = factory.getPair(address(USDC), token);
        ISomniaExchangePair(pair).approve(address(dexRouter), liquidity);

        (amountA, amountB) = dexRouter.removeLiquidity(
            address(USDC),
            token,
            liquidity,
            0,
            0,
            to,
            block.timestamp
        );
        emit LiquidityRemoved(token, to, amountA, amountB, block.timestamp);
    }

    function swapExactTokensForTokens(address token, uint256 amountIn, uint256 amountOutMin, address[] calldata path, address to)
        external
        onlyAuthorized(token)
        nonReentrant
        returns (uint256[] memory amounts)
    {
        require(to != address(0), "Invalid address");
        require(amountIn > 0, "Amount in must be greater than 0");

        IERC20(path[0]).approve(address(dexRouter), amountIn);

        amounts = dexRouter.swapExactTokensForTokens(
            amountIn,
            amountOutMin,
            path,
            to,
            block.timestamp
        );
        emit TokensSwapped(token, to, amounts[0], amounts[amounts.length - 1], path, block.timestamp);
    }

    function updateConfig(address newConfig) external onlyOwner {
        config = newConfig;
        emit ConfigUpdated(newConfig, block.timestamp);
    }

    function updateRouter(address newRouter) external onlyOwner {
        dexRouter = ISomniaExchangeRouter02(newRouter);
        emit RouterUpdated(newRouter, block.timestamp);
    }

    function _owner() internal view returns (address) {
        return Ownable(config).owner();
    }

    modifier onlyAuthorized(address token) {
        if (_msgSender() != _owner() && _msgSender() != token) revert Unauthorized();
        _;
    }
}

